#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding sleep-quality-assessment (14 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    ethnicity:string! \
    occupation:string! \
    shift_worker:string! \
    shift_pattern:string! \
    referring_physician:string! \
    referral_date:date \
    --htmx

cargo loco generate scaffold assessment_sleep_habits \
    assessment:references \
    usual_bedtime:string \
    usual_wake_time:string \
    time_in_bed_hours:double \
    nap_frequency:string! \
    nap_duration_minutes:int \
    sleep_environment_noise:string! \
    sleep_environment_light:string! \
    sleep_environment_temperature:string! \
    screen_use_before_bed:string! \
    screen_use_duration_minutes:int \
    bed_partner:string! \
    bed_partner_sleep_issues:text! \
    --htmx

cargo loco generate scaffold assessment_sleep_latency \
    assessment:references \
    time_to_fall_asleep_minutes:int \
    cannot_sleep_within_30_min:int \
    racing_thoughts_at_bedtime:string! \
    physical_discomfort_at_bedtime:string! \
    anxiety_at_bedtime:string! \
    difficulty_relaxing:string! \
    sleep_onset_strategies:text! \
    --htmx

cargo loco generate scaffold assessment_sleep_duration \
    assessment:references \
    actual_sleep_hours:double \
    sleep_duration_weekday_hours:double \
    sleep_duration_weekend_hours:double \
    sleep_duration_variability:string! \
    perceived_sleep_need_hours:double \
    sleep_debt_present:string! \
    --htmx

cargo loco generate scaffold assessment_sleep_efficiency \
    assessment:references \
    sleep_efficiency_percent:double \
    time_awake_in_bed_minutes:int \
    number_of_awakenings:int \
    time_to_return_to_sleep_minutes:int \
    early_morning_awakening:string! \
    early_awakening_time:string \
    difficulty_returning_to_sleep:string! \
    --htmx

cargo loco generate scaffold assessment_sleep_disturbances \
    assessment:references \
    wake_middle_of_night:int \
    bathroom_use:int \
    breathing_difficulty:int \
    cough_or_snore:int \
    feel_too_cold:int \
    feel_too_hot:int \
    bad_dreams:int \
    pain:int \
    other_disturbance:int \
    other_disturbance_description:text! \
    restless_legs:string! \
    sleep_talking:string! \
    sleep_walking:string! \
    teeth_grinding:string! \
    --htmx

cargo loco generate scaffold assessment_daytime_dysfunction \
    assessment:references \
    trouble_staying_awake:int \
    lack_of_enthusiasm:int \
    daytime_sleepiness_severity:int \
    epworth_sleepiness_score:int \
    concentration_difficulty:string! \
    memory_problems:string! \
    irritability:string! \
    morning_headaches:string! \
    drowsy_driving:string! \
    work_performance_impact:string! \
    --htmx

cargo loco generate scaffold assessment_sleep_medication_use \
    assessment:references \
    sleep_medication_frequency:int \
    prescribed_sleep_medication:string! \
    prescribed_medication_names:text! \
    prescribed_medication_dose:text! \
    prescribed_medication_duration_months:int \
    over_the_counter_sleep_aids:string! \
    otc_sleep_aid_details:text! \
    melatonin_use:string! \
    melatonin_dose_mg:double \
    herbal_supplements:string! \
    herbal_supplement_details:text! \
    caffeine_daily_intake:string! \
    caffeine_last_intake_time:string \
    alcohol_as_sleep_aid:string! \
    --htmx

cargo loco generate scaffold assessment_medical_lifestyle_factors \
    assessment:references \
    obstructive_sleep_apnoea:string! \
    cpap_use:string! \
    chronic_pain:string! \
    chronic_pain_details:text! \
    depression:string! \
    anxiety:string! \
    ptsd:string! \
    thyroid_disorder:string! \
    respiratory_disease:string! \
    cardiac_disease:string! \
    neurological_condition:string! \
    neurological_details:text! \
    exercise_frequency:string! \
    exercise_timing:string! \
    smoking_status:string! \
    alcohol_frequency:string! \
    stress_level:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    psqi_global_score:int \
    psqi_component1_subjective_quality:int \
    psqi_component2_sleep_latency:int \
    psqi_component3_sleep_duration:int \
    psqi_component4_sleep_efficiency:int \
    psqi_component5_sleep_disturbances:int \
    psqi_component6_sleep_medication:int \
    psqi_component7_daytime_dysfunction:int \
    sleep_quality_category:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
